script:
const content = document.getElementById('win-content-' + winObj.id);

// 1. 注入局部作用域样式：引入 iPad 滚动沙盒修补程序与层级重叠防护
const styleEl = document.createElement('style');
styleEl.innerHTML = `#win-content-${winObj.id} { --neon-green: #39ff14; --neon-blue: #00f2ff; background: #0a0a12; color: #e2e8f0; font-family: system-ui, -apple-system, sans-serif; height: 100%; width: 100%; overflow: hidden; } #win-content-${winObj.id} .pdf-container { display: flex; flex-direction: column; height: 100%; width: 100%; box-sizing: border-box; } #win-content-${winObj.id} .pdf-toolbar { background: #111122; border-bottom: 2px solid #222244; padding: 10px 16px; display: flex; align-items: center; justify-content: space-between; gap: 12px; z-index: 20; box-shadow: 0 4px 20px rgba(0,0,0,0.5); flex-shrink: 0; } #win-content-${winObj.id} .custom-file-upload { background: linear-gradient(135deg, #1e1e38 0%, #2d2d5a 100%); border: 1px solid var(--neon-blue); color: var(--neon-blue); padding: 6px 14px; font-size: 11px; font-weight: bold; border-radius: 4px; cursor: pointer; transition: all 0.2s; box-shadow: 0 0 10px rgba(0,242,255,0.2); } #win-content-${winObj.id} .custom-file-upload:hover { background: var(--neon-blue); color: #000; box-shadow: 0 0 15px var(--neon-blue); } #win-content-${winObj.id} .btn-zoom-out { background: transparent; border: 1px solid #444466; color: #94a3b8; padding: 5px 12px; font-size: 11px; border-radius: 4px; cursor: pointer; transition: all 0.2s; } #win-content-${winObj.id} .btn-zoom-out:not(:disabled):hover { border-color: var(--neon-green); color: var(--neon-green); box-shadow: 0 0 8px rgba(57,255,20,0.2); } #win-content-${winObj.id} .btn-zoom-out:disabled { opacity: 0.3; cursor: not-allowed; } #win-content-${winObj.id} .pdf-viewer-area { flex: 1; width: 100%; height: calc(100% - 55px); background: #151525; position: relative; overflow: hidden; } #win-content-${winObj.id} .ipad-scroll-wrapper { width: 100%; height: 100%; overflow-y: auto; -webkit-overflow-scrolling: touch; z-index: 10; position: absolute; inset: 0; } #win-content-${winObj.id} .pdf-frame { width: 100%; height: 100%; border: none; background: #151525; display: block; } #win-content-${winObj.id} .welcome-screen { position: absolute; inset: 0; display: flex; flex-direction: column; align-items: center; justify-content: center; text-align: center; padding: 24px; z-index: 15; background: #0a0a12; transition: opacity 0.3s ease; }`;
content.appendChild(styleEl);

// 2. 构造 HTML 核心骨架
content.innerHTML += `<div class="pdf-container"><div class="pdf-toolbar"><div class="flex items-center gap-3"><label class="custom-file-upload"><input type="file" id="file-input-${winObj.id}" accept="application/pdf" class="hidden">载入 PDF 文件</label><span id="file-name-${winObj.id}" class="text-xs text-slate-400 font-mono truncate max-w-[200px] md:max-w-[300px]">暂无载入的文档</span></div><div class="flex items-center gap-2"><button id="btn-fullscreen-${winObj.id}" class="btn-zoom-out" disabled>🔍 独立放大查看</button><div class="text-[10px] text-slate-500 font-mono tracking-wider uppercase hidden md:block">JROS Document Engine v1.3</div></div></div><div class="pdf-viewer-area"><div id="welcome-${winObj.id}" class="welcome-screen"><div class="text-5xl mb-4 animate-pulse">📄</div><h3 class="text-md font-bold text-cyan-400 tracking-wide mb-2">本地安全 PDF 阅读沙盒</h3><p class="text-xs text-slate-500 max-w-[340px] leading-relaxed">点击上方按钮从沙盒外载入 PDF 格式文件。文档将在 iPad/系统本地安全渲染，数据绝不上传。</p></div><div id="scroll-wrap-${winObj.id}" class="ipad-scroll-wrapper hidden"><iframe id="iframe-${winObj.id}" class="pdf-frame"></iframe></div></div></div>`;

// 3. 抓取视窗局部 DOM 引用
const fileInput = content.querySelector(`#file-input-${winObj.id}`);
const fileNameSpan = content.querySelector(`#file-name-${winObj.id}`);
const scrollWrap = content.querySelector(`#scroll-wrap-${winObj.id}`);
const pdfIframe = content.querySelector(`#iframe-${winObj.id}`);
const welcomeScreen = content.querySelector(`#welcome-${winObj.id}`);
const btnFullscreen = content.querySelector(`#btn-fullscreen-${winObj.id}`);

let currentPdfUrl = null;

// 4. 音频回馈组件
const triggerClickSound = (freq, type, duration) => {
  if (typeof playSystemSound === 'function') {
    playSystemSound(freq, type, duration);
  } else {
    try {
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      if (!AudioCtx) return;
      const audioCtx = new AudioCtx();
      const osc = audioCtx.createOscillator();
      const gain = audioCtx.createGain();
      osc.type = type || 'sine';
      osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
      gain.gain.setValueAtTime(0.05, audioCtx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
      osc.connect(gain);
      gain.connect(audioCtx.destination);
      osc.start();
      osc.stop(audioCtx.currentTime + duration);
    } catch (e) {}
  }
};

// 5. 核心流文件处理监听
fileInput.onchange = (e) => {
  const file = e.target.files[0];
  if (!file) return;

  if (file.type !== 'application/pdf') {
    triggerClickSound(180, 'sawtooth', 0.15);
    alert('错误：所选文件不是合法的 PDF 文档。');
    return;
  }

  if (currentPdfUrl) {
    URL.revokeObjectURL(currentPdfUrl);
  }

  triggerClickSound(587.33, 'triangle', 0.08);
  setTimeout(() => triggerClickSound(880, 'triangle', 0.12), 60);

  currentPdfUrl = URL.createObjectURL(file);

  fileNameSpan.innerText = file.name;
  fileNameSpan.className = 'text-xs text-emerald-400 font-mono truncate max-w-[200px] md:max-w-[300px]';

  welcomeScreen.style.display = 'none';
  scrollWrap.classList.remove('hidden');
  btnFullscreen.disabled = false;

  pdfIframe.src = currentPdfUrl;
};

// 6. 核心逻辑：弹出新页面并在顶部注入带有“退出”控制按钮的导航控制条
btnFullscreen.onclick = () => {
  if (!currentPdfUrl) return;
  triggerClickSound(659.25, 'sine', 0.08);
  const newWin = window.open();
  if (newWin) {
    const safeTitle = fileNameSpan.innerText.replace(/['"\\]/g, '');
    newWin.document.write(`<html lang="zh"><head><title>${safeTitle}</title><meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no"><style>body,html{margin:0;padding:0;width:100%;height:100%;display:flex;flex-direction:column;background:#151525;font-family:system-ui,-apple-system,sans-serif;} .nav-bar{background:#111122;border-bottom:2px solid #222244;padding:8px 16px;display:flex;align-items:center;justify-content:between;box-shadow:0 4px 15px rgba(0,0,0,0.4);flex-shrink:0;} .doc-title{color:#94a3b8;font-size:12px;font-family:monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-w:60%;} .btn-exit{background:linear-gradient(135deg,#7f1d1d 0%,#991b1b 100%);border:1px solid #ef4444;color:#fca5a5;padding:5px 14px;font-size:11px;font-weight:bold;border-radius:4px;cursor:pointer;box-shadow:0 0 8px rgba(239,68,68,0.2);transition:all 0.15s;} .btn-exit:hover{background:#ef4444;color:#fff;box-shadow:0 0 12px #ef4444;} .view-container{flex:1;width:100%;position:relative;overflow:hidden;} iframe{width:100%;height:100%;border:none;display:block;}</style></head><body><div class="nav-bar"><div class="doc-title">🔍 正在全屏无损查看: ${safeTitle}</div><button class="btn-exit" onclick="window.close()">退出查看</button></div><div class="view-container"><iframe src="${currentPdfUrl}"></iframe></div></body></html>`);
    newWin.document.close();
  } else {
    alert('提示：请允许系统弹出新标签页以进行无损放大浏览。');
  }
};

// 7. 阻止触摸事件向外穿透
scrollWrap.addEventListener('touchstart', (e) => { e.stopPropagation(); }, { passive: true });
scrollWrap.addEventListener('touchmove', (e) => { e.stopPropagation(); }, { passive: true });

// 8. 销毁防护器
winObj.onDestroy = () => {
  if (currentPdfUrl) {
    URL.revokeObjectURL(currentPdfUrl);
    currentPdfUrl = null;
  }
};
